import { Request, Response } from 'express';
import { injectable, inject } from 'inversify';
import { TYPES } from '@/config/inversify-key.types';
import code from '@/types/http-status.enum';
import { IAuthService } from '@/services/Interfaces/IAuth.service';
import {
    AuthMessages,
    ErrorMessages,
    SuccessMessages,
} from '@/types/response-messages.types';
import { UpdateUserStatusRequestDto } from '@/dto/request.dto';
import { IAdminAuthService } from '@/services/Interfaces/IAdmin-authService';
import { INotificationService } from '@/services/Interfaces/INotification.service';
import { IAdminService } from '@/services/Interfaces/IAdmin.service';
import { IWalletService } from '@/services/Interfaces/IWallet.service';

@injectable()
export class AdminController {
    constructor(
        @inject(TYPES.AdminAuthService)
        private _adminAuthService: IAdminAuthService,
        @inject(TYPES.NotificationService)
        private _notificationService: INotificationService,
        @inject(TYPES.AdminService)
        private _adminService: IAdminService,
        @inject(TYPES.AuthService)
        private _authService: IAuthService,
        @inject(TYPES.WalletService)
        private _walletService: IWalletService
    ) {}

    async getNotifications(req: Request, res: Response): Promise<void> {
        const notifications =
            await this._notificationService.getNotificationsByRecipient(
                'admin_global'
            );
        res.status(code.OK).json(notifications);
    }

    async markNotificationAsRead(req: Request, res: Response): Promise<void> {
        const { id } = req.params;
        await this._notificationService.markAsRead(id);
        res.status(code.OK).json({
            message: SuccessMessages.NotificationMarkedRead,
        });
    }

    async markAllNotificationsAsRead(
        req: Request,
        res: Response
    ): Promise<void> {
        await this._notificationService.markAllAsRead('admin_global');
        res.status(code.OK).json({
            message: SuccessMessages.AllNotificationsMarkedRead,
        });
    }

    async getMentorApplications(req: Request, res: Response): Promise<void> {
        const page = parseInt(req.query.page as string) || 1;
        const limit = parseInt(req.query.limit as string) || 10;
        const search = (req.query.search as string) || '';
        const status = (req.query.status as string) || 'all';
        const mentorType = (req.query.mentorType as string) || 'all';

        const applications = await this._adminService.getMentorApplications(
            page,
            limit,
            search,
            { status, mentorType }
        );
        res.status(code.OK).json(applications);
    }

    async getMentorApplicationById(req: Request, res: Response): Promise<void> {
        const { id } = req.params;
        const application =
            await this._adminService.getMentorApplicationById(id);
        if (!application) {
            res.status(code.NOT_FOUND).json({
                message: ErrorMessages.ApplicationNotFound,
            });
            return;
        }
        res.status(code.OK).json(application);
    }

    async approveMentorApplication(req: Request, res: Response): Promise<void> {
        const { id } = req.params;
        await this._adminService.approveMentorApplication(id);
        res.status(code.OK).json({
            message: SuccessMessages.ApplicationApproved,
        });
    }

    async rejectMentorApplication(req: Request, res: Response): Promise<void> {
        const { id } = req.params;
        const { reason } = req.body;
        await this._adminService.rejectMentorApplication(id, reason);
        res.status(code.OK).json({
            message: SuccessMessages.ApplicationRejected,
        });
    }

    async requestChangesMentorApplication(
        req: Request,
        res: Response
    ): Promise<void> {
        const { id } = req.params;
        const { reason } = req.body;
        await this._adminService.requestChangesMentorApplication(id, reason);
        res.status(code.OK).json({ message: SuccessMessages.ChangesRequested });
    }

    async adminLogin(req: Request, res: Response) {
        const response = await this._adminAuthService.adminLogin(req.body);
        res.cookie('refreshToken', response.refreshToken, {
            httpOnly: true,
            secure: true,
        });
        res.cookie('accessToken', response.accessToken, {
            httpOnly: true,
            secure: true,
        });
        res.status(code.OK).json({
            message: SuccessMessages.AdminLoginSuccess,
            admin: response.admin,
        });
    }

    async refreshTokenHandler(req: Request, res: Response) {
        try {
            const token = req.cookies.refreshToken;
            if (!token) {
                throw new Error('Last Session expired, Please login again');
            }
            const { accessToken, refreshToken } =
                await this._authService.refreshToken(token);

            res.cookie('accessToken', accessToken, {
                httpOnly: true,
                secure: true,
                sameSite: 'strict',
            });

            res.cookie('refreshToken', refreshToken, {
                httpOnly: true,
                secure: true,
                sameSite: 'strict',
            });

            res.json({ success: true });
        } catch (error: unknown) {
            const message =
                error instanceof Error
                    ? error.message
                    : ErrorMessages.TokenRefreshFailed;
            res.status(code.UNAUTHORIZED).json({ message });
        }
    }

    async logout(req: Request, res: Response) {
        try {
            res.clearCookie('refreshToken', {
                httpOnly: true,
                secure: process.env.NODE_ENV === 'production',
                sameSite: 'strict',
            });
            res.clearCookie('accessToken', {
                httpOnly: true,
                secure: process.env.NODE_ENV === 'production',
                sameSite: 'strict',
            });

            res.status(code.OK).json(AuthMessages.LogoutSuccess);
        } catch (error: unknown) {
            console.error('Logout error:', error);
            res.status(code.INTERNAL_SERVER_ERROR).json(
                AuthMessages.LogoutFailed
            );
        }
    }

    async getAllMentors(req: Request, res: Response): Promise<void> {
        const page = parseInt(req.query.page as string) || 1;
        const limit = parseInt(req.query.limit as string) || 10;
        const search = (req.query.search as string) || '';
        const status = (req.query.status as string) || 'all';
        const mentorType = (req.query.mentorType as string) || 'all';

        const mentors = await this._adminService.getAllMentors(
            page,
            limit,
            search,
            { status, mentorType }
        );
        res.status(code.OK).json(mentors);
    }

    async getMentorById(req: Request, res: Response): Promise<void> {
        const id = req.currentUser?.id;
        if (!id) {
            res.status(code.UNAUTHORIZED).json({
                message: ErrorMessages.UserNotFound,
            });
            return;
        }
        const mentor = await this._adminService.getMentorById(id);
        if (!mentor) {
            res.status(code.NOT_FOUND).json({
                message: ErrorMessages.MentorNotFound,
            });
            return;
        }
        res.status(code.OK).json(mentor);
    }

    async updateMentorStatus(req: Request, res: Response): Promise<void> {
        const { id } = req.params;
        const { status } = req.body;
        await this._adminService.updateMentorStatus(id, status);
        res.status(code.OK).json({
            message: SuccessMessages.MentorStatusUpdated,
        });
    }

    async getAllUsers(req: Request, res: Response): Promise<void> {
        const page = parseInt(req.query.page as string) || 1;
        const limit = parseInt(req.query.limit as string) || 10;
        const search = (req.query.search as string) || '';
        const result = await this._adminService.getAllUsers(
            page,
            limit,
            search
        );
        res.status(code.OK).json(result);
    }

    async updateUserStatus(req: Request, res: Response): Promise<void> {
        const id = req.params.id;
        const { isActive } = req.body;
        const dto = new UpdateUserStatusRequestDto(id, isActive);
        await this._adminService.updateUserStatus(dto);
        res.status(code.OK).json({
            message: SuccessMessages.UserStatusUpdated,
        });
    }

    async getRevenueData(req: Request, res: Response): Promise<void> {
        const id = req.currentUser?.id;
        const revenue = await this._adminService.getRevenueDetails(id!);
        res.status(code.OK).json(revenue);
    }

    async getTransactions(req: Request, res: Response): Promise<void> {
        const page = parseInt(req.query.page as string) || 1;
        const limit = parseInt(req.query.limit as string) || 10;
        const filter = (req.query.filter as 'all' | 'mentor' | 'user') || 'all';
        const transactions = await this._adminService.getAllTransactions(
            page,
            limit,
            filter
        );
        res.status(code.OK).json(transactions);
    }

    async getDashboardStats(req: Request, res: Response): Promise<void> {
        const id = req.currentUser?.id;
        if (!id) {
            res.status(code.UNAUTHORIZED).json({
                message: ErrorMessages.UserNotFound,
            });
            return;
        }
        const stats = await this._adminService.getDashboardStats(id);
        res.status(code.OK).json(stats);
    }

    async approveWithdrawal(req: Request, res: Response): Promise<void> {
        const { walletId, transactionId } = req.params;
        const wallet = await this._walletService.approveWithdrawal(
            walletId,
            transactionId
        );
        res.status(code.OK).json({
            message:
                'Payout approved and Stripe Express Transfer completed successfully.',
            wallet,
        });
    }

    async rejectWithdrawal(req: Request, res: Response): Promise<void> {
        const { walletId, transactionId } = req.params;
        const wallet = await this._walletService.rejectWithdrawal(
            walletId,
            transactionId
        );
        res.status(code.OK).json({
            message:
                'Payout request rejected and funds returned to mentor balance.',
            wallet,
        });
    }
}
